// ═══ MODELO ═══

export function getH2H(t1,t2){
  const k1=t1+'|'+t2,k2=t2+'|'+t1;
  if(H2H[k1])return{data:H2H[k1],t1First:true};
  if(H2H[k2])return{data:H2H[k2],t1First:false};
  return null;
}

export function getXG(team,asAtt,neutral,isHome,wcRealOverride){
  const wcSource=wcRealOverride||WC_REAL;
  const m=MODEL[team],wc=wcSource[team];
  if(!m)return asAtt?1.2:1.1;
  let base=asAtt
    ?(!neutral&&isHome&&m.homeGF!=null?m.homeGF:!neutral&&!isHome&&m.awayGF!=null?m.awayGF:m.avgGF)
    :(!neutral&&isHome&&m.homeGA!=null?m.homeGA:!neutral&&!isHome&&m.awayGA!=null?m.awayGA:m.avgGA);
  if(wc&&wc.pj>0){
    // Con pocos partidos jugados en el torneo, un resultado extremo (ej. 7-1) no debe dominar la cuota:
    // se limita el valor a un rango razonable y se usa una mezcla que exige más partidos para ganar peso real.
    const wv=Math.min(4,Math.max(0.3,asAtt?wc.avgGF:wc.avgGA));
    const wr=wc.pj/(wc.pj+5); // 1 partido→~17%, 2→~29%, crece gradualmente con más partidos
    base=base*(1-wr)+wv*wr;
  }
  return Math.max(0.15,base);
}

// Probabilidad de que el total de goles supere una línea cualquiera (no solo 2.5) — para cuando
// la casa de apuestas (ej. Coolbet) ofrece una línea distinta según cuán parejo está el partido.
export function overProb(xgH,xgA,line){
  const poi=(l,k)=>{let p=Math.exp(-l);for(let i=0;i<k;i++)p*=l/(i+1);return p;};
  let pO=0;
  for(let i=0;i<=10;i++)for(let j=0;j<=10;j++){
    if(i+j>line) pO+=poi(xgH,i)*poi(xgA,j);
  }
  return pO;
}

// rotationOverride: { home: number; away: number } — multiplicador sobre xG atacante de cada equipo.
// Calculado en /api/lineup-changes comparando alineaciones del partido actual vs anterior vs antepenúltimo.
export function modelProbs(home,away,neutral,wcRealOverride,h2hOverride,rotationOverride?){
  const mH=MODEL[home]||{avgGF:1.35,avgGA:1.1,elo:1500};
  const mA=MODEL[away]||{avgGF:1.35,avgGA:1.1,elo:1500};
  const eloH=(mH.elo||1500)+(neutral?0:60);
  const eloA=mA.elo||1500;
  const eloExpH=1/(1+Math.pow(10,(eloA-eloH)/400));
  const eloExpA=1-eloExpH;
  let xgH=Math.max(0.15,(getXG(home,true,neutral,true,wcRealOverride)*getXG(away,false,neutral,false,wcRealOverride))/LEAGUE_AVG);
  let xgA=Math.max(0.15,(getXG(away,true,neutral,false,wcRealOverride)*getXG(home,false,neutral,true,wcRealOverride))/LEAGUE_AVG);
  // Ajuste por rotación: si el partido anterior de un equipo fue rotación masiva, su xG base está
  // contaminado por ese partido → se aplica un boost. Si hoy rotan, se penaliza.
  if(rotationOverride){
    xgH=Math.max(0.15,xgH*(rotationOverride.home??1));
    xgA=Math.max(0.15,xgA*(rotationOverride.away??1));
  }
  let hdData,hdT1First;
  if(h2hOverride&&h2hOverride.n>0){ hdData=h2hOverride; hdT1First=true; }
  else { const hd=getH2H(home,away); if(hd){ hdData=hd.data; hdT1First=hd.t1First; } }
  if(hdData&&hdData.n>=3){
    xgH=xgH*.85+(hdT1First?hdData.avgGF1:hdData.avgGA1)*.15;
    xgA=xgA*.85+(hdT1First?hdData.avgGA1:hdData.avgGF1)*.15;
  }
  const poi=(l,k)=>{let p=Math.exp(-l);for(let i=0;i<k;i++)p*=l/(i+1);return p;};
  let pH=0,pD=0,pA=0,pO=0,pB=0;
  const scores:{h:number;a:number;p:number}[]=[];
  for(let i=0;i<=10;i++)for(let j=0;j<=10;j++){
    const p=poi(xgH,i)*poi(xgA,j);
    if(i>j)pH+=p;else if(i===j)pD+=p;else pA+=p;
    if(i+j>2.5)pO+=p;
    if(i>0&&j>0)pB+=p;
    if(i<=6&&j<=6)scores.push({h:i,a:j,p});
  }
  const exactScores=scores.sort((a,b)=>b.p-a.p).slice(0,6);
  const bH=0.5*pH+0.5*eloExpH*(1-pD);
  const bA=0.5*pA+0.5*eloExpA*(1-pD);
  const bD=Math.max(0,1-bH-bA);
  return{home:bH,draw:bD,away:bA,over25:pO,under25:1-pO,btts:pB,xgH,xgA,eloH:mH.elo||1500,eloA:mA.elo||1500,exactScores};
}

// ═══ BEST PICK ═══
export function bestPick(home,away,p){
  const opts=[
    {label:'Gana '+home,prob:p.home},
    {label:'Empate',prob:p.draw},
    {label:'Gana '+away,prob:p.away},
    {label:'Over 2.5',prob:p.over25},
    {label:'Under 2.5',prob:p.under25},
    {label:'BTTS Sí',prob:p.btts},
  ];
  const winner=opts.slice(0,3).reduce((a,b)=>a.prob>b.prob?a:b);
  return winner.prob>=0.38?winner:opts.reduce((a,b)=>a.prob>b.prob?a:b);
}

